import React from 'react';
import { Link } from 'react-router-dom';

const Footer = () => {
    const currentYear = new Date().getFullYear();

    return (
        <footer style={styles.footerContainer}>
            <div style={styles.contentWrapper}>

                {/* Texto de Copyright principal */}
                <p style={styles.copyrightText}>
                    © {currentYear} Repositorio Bicentenario de Bolivia. Todos los derechos reservados.
                </p>

                {/* Contenido principal: Navegación y Redes Sociales en dos columnas */}
                <div style={styles.mainContentFlex}>

                    {/* Columna Izquierda: Navegación */}
                    <div style={styles.navigationSection}>
                        <h3 style={styles.sectionTitle}>NAVEGACIÓN</h3>
                        <ul style={styles.linkList}>
                            <li><Link to="/acerca-de" style={styles.link}>Acerca de</Link></li>
                            <li><Link to="/mas-de-nosotros" style={styles.link}>Más de Nosotros</Link></li>
                            <li><Link to="/contacto" style={styles.link}>Contacto</Link></li>
                        </ul>
                    </div>

                    {/* Columna Derecha: Solo Íconos de Redes Sociales (sin título "REDES SOCIALES") */}
                    <div style={styles.socialIconsSection}>
                        {/* **IMPORTANTE:** Asegúrate de que estos archivos PNG existan en public/media/icons/ */}
                        <a href="https://www.facebook.com/TuPaginaDeFacebook" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                            <img src="/media/icons/facebook_icon.png" alt="Facebook" style={styles.socialIconImage} />
                        </a>
                        <a href="https://www.instagram.com/TuCuentaDeInstagram" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                            <img src="/media/icons/instagram_icon.png" alt="Instagram" style={styles.socialIconImage} />
                        </a>
                        <a href="https://www.tiktok.com/@TuCuentaDeTikTok" target="_blank" rel="noopener noreferrer" style={styles.socialIconLink}>
                            <img src="/media/icons/tiktok_icon.png" alt="TikTok" style={styles.socialIconImage} />
                        </a>
                    </div>

                </div>

                {/* Línea divisoria */}
                <div style={styles.divider}></div>

                {/* Cita final */}
                <p style={styles.quoteText}>
                    “Conocer nuestra historia es entender nuestro presente.”
                </p>

                {/* Crédito de Alberto Navarro */}
                <p style={styles.navarroCredit}>Titulizado por Alberto Navarro</p>

            </div>
        </footer>
    );
};

const styles = {
    footerContainer: {
        backgroundColor: '#F8F6F1', // Un beige suave como color de fondo fijo
        color: '#4a4a4a', // Color de texto principal
        fontFamily: "'Inter', sans-serif", // Fuente que imita el estilo moderno
        padding: '10px 0', // MUCHO MENOS padding vertical para ser muy compacto
        marginTop: 'auto', // Para que se pegue al final de la página
        boxShadow: '0 -1px 5px rgba(0,0,0,0.01)', // Sombra aún más sutil
        fontSize: '0.8rem', // Tamaño de fuente general más pequeño
        lineHeight: '1.3',
        minHeight: '120px', // Altura mínima para asegurar visibilidad sin ser intrusivo
        display: 'flex', // Para centrar el contenido verticalmente
        alignItems: 'center', // Centra el contenido verticalmente
        flexDirection: 'column', // Asegura que los elementos internos se apilen si es necesario
        justifyContent: 'center', // Centra el contenido si hay espacio extra
    },
    contentWrapper: {
        maxWidth: '550px', // Ancho máximo más pequeño para un diseño más centralizado
        margin: '0 auto',
        padding: '0 10px', // Padding horizontal mínimo
        textAlign: 'center', // Todo el texto centrado
        width: '100%', // Ocupa el ancho disponible dentro del maxWidth
    },
    copyrightText: {
        fontSize: '0.75rem', // Tamaño de copyright
        color: '#555',
        marginBottom: '10px', // Espacio abajo del copyright
        textAlign: 'center',
        fontWeight: 'normal',
    },
    mainContentFlex: {
        display: 'flex',
        flexWrap: 'wrap', // Permite que las columnas se envuelvan en pantallas pequeñas
        justifyContent: 'center', // Centra las secciones en el contenedor
        alignItems: 'flex-start', // Alinea los ítems en la parte superior de su línea
        gap: '40px', // Gran espacio entre las dos columnas (Navegación e Íconos)
        marginBottom: '10px', // Menos espacio antes de la línea divisoria
        width: '100%', // Ocupa el ancho completo dentro del contentWrapper
    },
    navigationSection: {
        flex: '0 0 auto', // La sección se ajusta a su contenido
        padding: '0', // Sin padding extra
        textAlign: 'center', // Títulos y enlaces centrados
    },
    socialIconsSection: { // Nueva sección para los íconos de redes sociales
        flex: '0 0 auto',
        padding: '0', // Sin padding extra
        textAlign: 'center',
        marginTop: '25px', // Ajuste para que los íconos queden al nivel de la lista de navegación
    },
    sectionTitle: {
        fontSize: '0.8rem', // Títulos muy pequeños
        fontWeight: 'bold',
        marginBottom: '8px', // Menos margen abajo del título
        textTransform: 'uppercase',
        color: '#222',
    },
    linkList: {
        listStyle: 'none',
        padding: 0,
        margin: 0,
        lineHeight: '1.1', // Reduce el espaciado entre ítems de la lista para compactar
    },
    link: {
        textDecoration: 'none',
        color: '#555',
        fontSize: '0.75rem', // Tamaño de fuente para enlaces muy pequeño
        transition: 'color 0.2s ease',
        display: 'block', // Hace que los enlaces sean bloques para ocupar su propia línea
        padding: '2px 0', // Pequeño padding vertical para cada enlace
        '&:hover': {
            color: '#1e7e34', // Un verde
        },
    },
    socialIcons: {
        display: 'flex',
        justifyContent: 'center', // Centrar los íconos dentro de su contenedor
        gap: '12px', // Espacio entre los íconos
        marginTop: '0', // Eliminado margen superior extra
    },
    socialIconLink: {
        textDecoration: 'none',
        display: 'inline-block',
    },
    socialIconImage: {
        width: '16px', // Íconos aún más pequeños para el look compacto
        height: '16px',
        opacity: 0.8,
        transition: 'opacity 0.2s ease, transform 0.1s ease',
        '&:hover': {
            opacity: 1,
            transform: 'scale(1.1)',
        },
    },
    divider: {
        borderBottom: '1px solid rgba(200,200,200,0.4)', // Línea divisoria sutil
        width: '60%', // Ancho de la línea
        margin: '10px auto 8px auto', // Centrar y espacio reducido
    },
    quoteText: {
        fontSize: '0.7rem', // Tamaño de fuente para la cita muy pequeña
        fontStyle: 'italic',
        color: '#777',
        margin: '0 0 5px 0', // Menos margen
        textAlign: 'center',
    },
    navarroCredit: {
        fontSize: '0.6rem', // Muy pequeño y discreto
        color: '#888',
        marginTop: '0',
        textAlign: 'center',
    }
};

export default Footer;
